module mux32to1 (
    input [31:0] obf_in,      // 32 data inputs
    input [4:0] sel,      // 5-bit select line
    output reg out        // 1 output
);
    always @(*) begin
        case (sel)
            5'b00000: out = obf_in[0];
            5'b00001: out = obf_in[1];
            5'b00010: out = obf_in[2];
            5'b00011: out = obf_in[3];
            5'b00100: out = obf_in[4];
            5'b00101: out = obf_in[5];
            5'b00110: out = obf_in[6];
            5'b00111: out = obf_in[7];
            5'b01000: out = obf_in[8];
            5'b01001: out = obf_in[9];
            5'b01010: out = obf_in[10];
            5'b01011: out = obf_in[11];
            5'b01100: out = obf_in[12];
            5'b01101: out = obf_in[13];
            5'b01110: out = obf_in[14];
            5'b01111: out = obf_in[15];
            5'b10000: out = obf_in[16];
            5'b10001: out = obf_in[17];
            5'b10010: out = obf_in[18];
            5'b10011: out = obf_in[19];
            5'b10100: out = obf_in[20];
            5'b10101: out = obf_in[21];
            5'b10110: out = obf_in[22];
            5'b10111: out = obf_in[23];
            5'b11000: out = obf_in[24];
            5'b11001: out = obf_in[25];
            5'b11010: out = obf_in[26];
            5'b11011: out = obf_in[27];
            5'b11100: out = obf_in[28];
            5'b11101: out = obf_in[29];
            5'b11110: out = obf_in[30];
            5'b11111: out = obf_in[31];
            default: out = 1'b0; // Default case
        endcase
    end
endmodule
